import{_ as o,o as a,c as i,ai as l}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"渠道位置解析","description":"","frontmatter":{"read_when":["添加或修改渠道位置解析","在智能体提示或工具中使用位置上下文字段"],"summary":"入站渠道位置解析（Telegram + WhatsApp）及上下文字段","title":"渠道位置解析","x-i18n":{"generated_at":"2026-02-01T19:21:46Z","model":"claude-opus-4-5","provider":"pi","source_hash":"5602ef105c3da7e47497bfed8fc343dd8d7f3c019ff7e423a08b25092c5a1837","source_path":"channels/location.md","workflow":14}},"headers":[],"relativePath":"zh-CN/channels/location.md","filePath":"zh-CN/channels/location.md","lastUpdated":1771906665000}'),c={name:"zh-CN/channels/location.md"};function n(s,e,d,t,r,p){return a(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="渠道位置解析" tabindex="-1"><a class="header-anchor" href="#渠道位置解析">#</a> 渠道位置解析</h1><p>OpenSoul 将聊天渠道中分享的位置标准化为：</p><ul><li>附加到入站消息体的可读文本，以及</li><li>自动回复上下文负载中的结构化字段。</li></ul><p>目前支持：</p><ul><li><strong>Telegram</strong>（位置图钉 + 地点 + 实时位置）</li><li><strong>WhatsApp</strong>（locationMessage + liveLocationMessage）</li><li><strong>Matrix</strong>（<code>m.location</code> 配合 <code>geo_uri</code>）</li></ul><h2 id="文本格式" tabindex="-1"><a class="header-anchor" href="#文本格式">#</a> 文本格式</h2><p>位置以友好的行格式呈现，不带括号：</p><ul><li>图钉： <ul><li><code>📍 48.858844, 2.294351 ±12m</code></li></ul></li><li>命名地点： <ul><li><code>📍 Eiffel Tower — Champ de Mars, Paris (48.858844, 2.294351 ±12m)</code></li></ul></li><li>实时分享： <ul><li><code>🛰 Live location: 48.858844, 2.294351 ±12m</code></li></ul></li></ul><p>如果渠道包含标题/评论，会附加在下一行：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>📍 48.858844, 2.294351 ±12m</span></span>
<span class="line"><span>Meet here</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="上下文字段" tabindex="-1"><a class="header-anchor" href="#上下文字段">#</a> 上下文字段</h2><p>当存在位置信息时，以下字段会被添加到 <code>ctx</code> 中：</p><ul><li><code>LocationLat</code>（数字）</li><li><code>LocationLon</code>（数字）</li><li><code>LocationAccuracy</code>（数字，米；可选）</li><li><code>LocationName</code>（字符串；可选）</li><li><code>LocationAddress</code>（字符串；可选）</li><li><code>LocationSource</code>（<code>pin | place | live</code>）</li><li><code>LocationIsLive</code>（布尔值）</li></ul><h2 id="渠道说明" tabindex="-1"><a class="header-anchor" href="#渠道说明">#</a> 渠道说明</h2><ul><li><strong>Telegram</strong>：地点映射到 <code>LocationName/LocationAddress</code>；实时位置使用 <code>live_period</code>。</li><li><strong>WhatsApp</strong>：<code>locationMessage.comment</code> 和 <code>liveLocationMessage.caption</code> 作为标题行附加。</li><li><strong>Matrix</strong>：<code>geo_uri</code> 解析为图钉位置；忽略海拔高度，<code>LocationIsLive</code> 始终为 false。</li></ul>`,15)])])}const m=o(c,[["render",n]]);export{u as __pageData,m as default};
